// Solution
function solve(n) {
  if (n <= 1) return n;
  else return n === 2 ? 1 : n === 3 ? 2 : fibonacci(n-1) + fibonacci(n-2);
}
function fibonacci(n) {
  let memo = new Array(n+1).fill(0);
  memo[1] = 1;
  for (let i = 2; i <= n; i++) {
    memo[i] = memo[i-1] + memo[i-2];
  }
  return memo[n];
}
